&lt;p&gt;[1] &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9jdGYtd2lraS5vcmcvcHduL2xpbnV4L3VzZXItbW9kZS9zdGFja292ZXJmbG93L3g4Ni9zdGFjay1pbnRyby8=&#34;&gt;https://ctf-wiki.org/pwn/linux/user-mode/stackoverflow/x86/stack-intro/&lt;/span&gt;&lt;/p&gt;
